import sys
import os
import json
from pathlib import Path

WEBFORGE_HOME = Path.home() / "webforge"
sys.path.insert(0, str(WEBFORGE_HOME / "agents"))
sys.path.insert(0, str(WEBFORGE_HOME / "mcp"))

from base import Agent


class VerdictFenn(Agent):
    """Auto-generated agent script for VerdictFenn."""

    name = "VerdictFenn"
    department = "Quality"
    skill_file = "quality/verdict-fenn.md"
    reports_to = "Minos"
    can_route_to = ["Minos", "Hermes", "Hephaestus"]

    allowed_actions = ["run_quality_check", "review_code", "answer_question", "route", "respond"]
    forbidden_actions = ["write_code", "create_bugfix_task", "create_feature_task", "run_standup", "research", "generate_docs", "learn"]

    # Per-agent correction rules (Daedalus patches these)
    correction_rules = []

    def execute(self, action, data, context):
        """Execute the action. CODE, not AI."""
        if action == "answer_question":
            return {
                "agent": self.name,
                "action": action,
                "message": f"I am {self.name} ({self.department}). I'm ready to work.",
                "next_step": None,
            }
        elif action == "route":
            return self._route_to(data.get("target", "Hermes"), data.get("message", ""))
        return {
            "agent": self.name,
            "action": action,
            "message": f"I am {self.name}. Action: {action}",
            "next_step": None,
        }


def run(message, context=None):
    """Called when developer talks to VerdictFenn."""
    agent = VerdictFenn()
    return agent.run(message, context)


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("VerdictFenn Agent — Quality")
